set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="推特中文圈 AI 自媒体博主"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 8 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 8 条规则:
  • 如果 发完蹲评论、作者主动回复 → 则 ：reply/作者回复是最高权重。案例：发完 1 小时内回前几条评论、抛追问引讨论——算法加权 + 涨粉。evidenc
  • 如果 AI 出初稿、人写洞察终稿 → 则 ：全自动只作快讯探针。案例：AI 快速编译一条模型发布快讯，深度 thread 必人工加实测与观点，不全自动。evide
  • 如果 外链放自回复第二条，正文不放链 → 则 ：避降权。案例：主推放结论 + ray.so 截图，论文/产品链接放 reply 第二条，避免非 Premium 近 0
  • 如果 选题盯英文一手 + 抢时间差 + 加本地洞察 → 则 ：用 RSS/Folo。案例：arXiv/官博一出，第一时间编译 + 加"对中文开发者意味着什么"，吃信息差。evide
  • 如果 配图用 ray.so/carbon + 截图美化，避撞脸 → 则 ：标配但别同质。案例：代码/文字用 carbon，产品用 Shottr 截图，别全用同款渐变图。evidence: [T
  • 如果 build in public 建信任飞轮 → 则 ：公开过程 + 透明数据。案例：独立开发者持续晒 MRR/踩坑/迭代，用真实进展换关注，比纯干货涨粉稳。evidence
  • 如果 锐评博 reply 红利但守底线 → 则 ：别踩举报 −369。案例：有理有据的观点锐评能引爆讨论，但人身攻击/标题党会招举报反噬触达。evidence: [T0
  • 如果 数字/算法值当 disputed 用 → 则 ：标"可能已变"。案例：引"reply=27/作者回复=75"时注明"2023 开源旧版，2026 已迁 Grok 排序

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "发完蹲评论、作者主动回复"
  "AI 出初稿、人写洞察终稿"
  "外链放自回复第二条，正文不放链"
  "选题盯英文一手 + 抢时间差 + 加本地洞察"
  "配图用 ray.so/carbon + 截图美化，避撞脸"
  "build in public 建信任飞轮"
  "锐评博 reply 红利但守底线"
  "数字/算法值当 disputed 用"
)
declare -a RULE_ACTIONS=(
  "：reply/作者回复是最高权重。案例：发完 1 小时内回前几条评论、抛追问引讨论——算法加权 + 涨粉。evidence: [T04-S002, T01-S005]"
  "：全自动只作快讯探针。案例：AI 快速编译一条模型发布快讯，深度 thread 必人工加实测与观点，不全自动。evidence: [T03-S001, T05-S002]"
  "：避降权。案例：主推放结论 + ray.so 截图，论文/产品链接放 reply 第二条，避免非 Premium 近 0 曝光。evidence: [T04-S002, T02-S001]"
  "：用 RSS/Folo。案例：arXiv/官博一出，第一时间编译 + 加\"对中文开发者意味着什么\"，吃信息差。evidence: [T05-S001, T04-S005]"
  "：标配但别同质。案例：代码/文字用 carbon，产品用 Shottr 截图，别全用同款渐变图。evidence: [T02-S001]"
  "：公开过程 + 透明数据。案例：独立开发者持续晒 MRR/踩坑/迭代，用真实进展换关注，比纯干货涨粉稳。evidence: [T01-S004, T05-S005]"
  "：别踩举报 −369。案例：有理有据的观点锐评能引爆讨论，但人身攻击/标题党会招举报反噬触达。evidence: [T04-S002, T06-S001]"
  "：标\"可能已变\"。案例：引\"reply=27/作者回复=75\"时注明\"2023 开源旧版，2026 已迁 Grok 排序，精确值存疑\"。evidence: [T04-S002, T05-S002]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
